// jobs/page.tsx — two-column split
// LEFT  (sticky, 38%) → HeroLeft  — big type + stats
// RIGHT (scrollable)  → Navbar + SearchBar + FilterSidebar + JobSections

import { Navbar }        from '@/components/layout/Navbar'
import { SearchBar }     from './components/SearchBar'
import { FilterSidebar } from './components/FilterSidebar'
import { JobSections }   from './components/JobSections'
import { HeroLeft }      from './components/HeroLeft'

export default function JobsPage() {
  return (
    <div className="flex min-h-screen bg-[#f7f3ef]">

      {/* ── LEFT — sticky hero panel ─────────────────────────────── */}
      <aside className="hidden lg:flex sticky top-0 h-screen w-[38%] max-w-[480px] shrink-0 border-r border-[#d4c4b5]">
        <HeroLeft />
      </aside>

      {/* ── RIGHT — scrollable content ───────────────────────────── */}
      <div className="flex-1 min-w-0 flex flex-col">
        <Navbar />

        {/* Search bar pinned under navbar */}
        <div className="sticky top-0 z-10 bg-[#f7f3ef]/90 backdrop-blur-sm border-b border-[#d4c4b5] px-6 py-3">
          <SearchBar />
        </div>

        {/* Filter + Jobs */}
        <main className="flex gap-6 px-6 py-6 flex-1 items-start">
          <FilterSidebar />
          <div className="flex-1 min-w-0">
            <JobSections />
          </div>
        </main>
      </div>

    </div>
  )
}